// MARK: - Crypto Utilities

struct CryptoUtils {
    
    /// Generate cryptographically secure random bytes
    static func generateRandomBytes(count: Int) -> Data? {
        var bytes = [UInt8](repeating: 0, count: count)
        let status = SecRandomCopyBytes(kSecRandomDefault, count, &bytes)
        guard status == errSecSuccess else { return nil }
        return Data(bytes)
    }
    
    /// Generate a 32-byte salt
    static func generateSalt() -> Data? {
        return generateRandomBytes(count: 32)
    }
    
    /// PBKDF2-HMAC-SHA256 key derivation
    static func pbkdf2(password: String,
                       salt: Data,
                       iterations: UInt32 = 100_000,
                       keyLength: Int = 32) -> Data? {
        guard let passwordData = password.data(using: .utf8) else { return nil }
        
        var derivedKey = [UInt8](repeating: 0, count: keyLength)
        
        let status = passwordData.withUnsafeBytes { passwordBytes -> Int32 in
            salt.withUnsafeBytes { saltBytes -> Int32 in
                guard let passwordPtr = passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                      let saltPtr = saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                    return -1
                }
                return CCKeyDerivationPBKDF(
                    CCPBKDFAlgorithm(kCCPBKDF2),
                    passwordPtr,
                    passwordData.count,
                    saltPtr,
                    salt.count,
                    CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                    iterations,
                    &derivedKey,
                    keyLength
                )
            }
        }
        
        guard status == kCCSuccess else { return nil }
        return Data(derivedKey)
    }
    
    /// Constant-time comparison to prevent timing attacks
    static func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        return result == 0
    }
}

// MARK: - Password Entry Model

struct PasswordEntry: Codable {
    let username: String
    let salt: Data
    let derivedKey: Data
    let iterations: UInt32
    let keyLength: Int
    let createdAt: Date
    let algorithm: String // For future-proofing
    
    init(username: String, salt: Data, derivedKey: Data, iterations: UInt32 = 100_000, keyLength: Int = 32) {
        self.username = username
        self.salt = salt
        self.derivedKey = derivedKey
        self.iterations = iterations
        self.keyLength = keyLength
        self.createdAt = Date()
        self.algorithm = "PBKDF2-HMAC-SHA256"
    }
}

// MARK: - Keychain Manager

final class KeychainManager {
    
    static let shared = KeychainManager()
    private let serviceIdentifier = "com.passwordstorage.credentials"
    
    private init() {}
    
    /// Save data to Keychain
    func save(data: Data, forKey key: String) -> Bool {
        // Delete existing item first
        delete(forKey: key)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    /// Load data from Keychain
    func load(forKey key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    /// Delete data from Keychain
    @discardableResult
    func delete(forKey key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
    
    /// Check if a key exists
    func exists(forKey key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: key,
            kSecReturnData as String: false
        ]
        
        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }
}

// MARK: - Password Storage Manager

enum PasswordStorageError: Error, LocalizedError {
    case saltGenerationFailed
    case hashingFailed
    case encodingFailed
    case decodingFailed
    case keychainSaveFailed
    case userNotFound
    case invalidPassword
    case passwordTooShort
    case passwordTooLong
    
    var errorDescription: String? {
        switch self {
        case .saltGenerationFailed: return "Failed to generate cryptographic salt"
        case .hashingFailed: return "Failed to hash password"
        case .encodingFailed: return "Failed to encode password entry"
        case .decodingFailed: return "Failed to decode password entry"
        case .keychainSaveFailed: return "Failed to save to Keychain"
        case .userNotFound: return "User not found"
        case .invalidPassword: return "Invalid password"
        case .passwordTooShort: return "Password must be at least 8 characters"
        case .passwordTooLong: return "Password must be at most 128 characters"
        }
    }
}

final class PasswordStorageManager {
    
    static let shared = PasswordStorageManager()
    
    private let keychain = KeychainManager.shared
    private let iterations: UInt32 = 100_000
    private let keyLength: Int = 32
    private let minPasswordLength = 8
    private let maxPasswordLength = 128
    private let userListKey = "registered_users_list"
    
    private init() {}
    
    // MARK: - Password Validation
    
    private func validatePassword(_ password: String) throws {
        guard password.count >= minPasswordLength else {
            throw PasswordStorageError.passwordTooShort
        }
        guard password.count <= maxPasswordLength else {
            throw PasswordStorageError.passwordTooLong
        }
    }
    
    // MARK: - User Registration
    
    /// Register a new user with a password
    func registerUser(username: String, password: String) throws {
        try validatePassword(password)
        
        // Normalize username
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        
        // Generate cryptographically secure salt
        guard let salt = CryptoUtils.generateSalt() else {
            throw PasswordStorageError.saltGenerationFailed
        }
        
        // Derive key using PBKDF2
        guard let derivedKey = CryptoUtils.pbkdf2(
            password: password,
            salt: salt,
            iterations: iterations,
            keyLength: keyLength
        ) else {
            throw PasswordStorageError.hashingFailed
        }
        
        // Create password entry
        let entry = PasswordEntry(
            username: normalizedUsername,
            salt: salt,
            derivedKey: derivedKey,
            iterations: iterations,
            keyLength: keyLength
        )
        
        // Encode and save to Keychain
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        
        guard let entryData = try? encoder.encode(entry) else {
            throw PasswordStorageError.encodingFailed
        }
        
        let keychainKey = keychainKeyForUser(normalizedUsername)
        guard keychain.save(data: entryData, forKey: keychainKey) else {
            throw PasswordStorageError.keychainSaveFailed
        }
        
        // Track registered users
        addToUserList(normalizedUsername)
    }
    
    // MARK: - Password Verification
    
    /// Verify a password for offline authentication
    func verifyPassword(username: String, password: String) throws -> Bool {
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        let keychainKey = keychainKeyForUser(normalizedUsername)
        
        // Load stored entry
        guard let entryData = keychain.load(forKey: keychainKey) else {
            throw PasswordStorageError.userNotFound
        }
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        
        guard let entry = try? decoder.decode(PasswordEntry.self, from: entryData) else {
            throw PasswordStorageError.decodingFailed
        }
        
        // Derive key with same parameters
        guard let derivedKey = CryptoUtils.pbkdf2(
            password: password,
            salt: entry.salt,
            iterations: entry.iterations,
            keyLength: entry.keyLength
        ) else {
            throw PasswordStorageError.hashingFailed
        }
        
        // Constant-time comparison
        return CryptoUtils.constantTimeCompare(derivedKey, entry.derivedKey)
    }
    
    // MARK: - Password Update
    
    /// Update password for an existing user (requires old password verification)
    func updatePassword(username: String, oldPassword: String, newPassword: String) throws {
        // Verify old password first
        let isValid = try verifyPassword(username: username, password: oldPassword)
        guard isValid else {
            throw PasswordStorageError.invalidPassword
        }
        
        try validatePassword(newPassword)
        
        // Delete old entry and create new one
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        keychain.delete(forKey: keychainKeyForUser(normalizedUsername))
        
        try registerUser(username: normalizedUsername, password: newPassword)
    }
    
    // MARK: - User Management
    
    /// Delete a user's stored credentials
    func deleteUser(username: String) {
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        keychain.delete(forKey: keychainKeyForUser(normalizedUsername))
        removeFromUserList(normalizedUsername)
    }
    
    /// Check if a user exists
    func userExists(username: String) -> Bool {
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        return keychain.exists(forKey: keychainKeyForUser(normalizedUsername))
    }
    
    /// Get list of registered usernames
    func registeredUsers() -> [String] {
        guard let data = keychain.load(forKey: userListKey),
              let users = try? JSONDecoder().decode([String].self, from: data) else {
            return []
        }
        return users
    }
    
    /// Delete all stored credentials
    func deleteAllUsers() {
        let users = registeredUsers()
        for user in users {
            keychain.delete(forKey: keychainKeyForUser(user))
        }
        keychain.delete(forKey: userListKey)
    }
    
    // MARK: - Private Helpers
    
    private func keychainKeyForUser(_ username: String) -> String {
        return "user_credential_\(username)"
    }
    
    private func addToUserList(_ username: String) {
        var users = registeredUsers()
        if !users.contains(username) {
            users.append(username)
        }
        if let data = try? JSONEncoder().encode(users) {
            keychain.save(data: data, forKey: userListKey)
        }
    }
    
    private func removeFromUserList(_ username: String) {
        var users = registeredUsers()
        users.removeAll { $0 == username }
        if let data = try? JSONEncoder().encode(users) {
            keychain.save(data: data, forKey: userListKey)
        }
    }
}

