            showStatus("Please enter username and password", isError: true)
            return
        }
        
        if passwordManager.userExists(username: username) {
            showStatus("User '\(username)' already exists", isError: true)
            return
        }
        
        setLoading(true)
        
        // Perform hashing on background thread (PBKDF2 is intentionally slow)
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            do {
                try self?.passwordManager.registerUser(username: username, password: password)
                DispatchQueue.main.async {
                    self?.setLoading(false)
                    self?.showStatus("User '\(username)' registered successfully! ✅", isError: false)
                    self?.passwordTextField.text = ""
                    self?.updateRegisteredUsersLabel()
                }
            } catch {
                DispatchQueue.main.async {
                    self?.setLoading(false)
                    self?.showStatus("Registration failed: \(error.localizedDescription)", isError: true)
                }
            }
        }
    }
    
