        guard let username = usernameTextField.text, !username.isEmpty,
              let password = passwordTextField.text, !password.isEmpty else {
            showStatus("Please enter username and password", isError: true)
            return
        }
        
        setLoading(true)
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            do {
                let isValid = try self?.passwordManager.verifyPassword(username: username, password: password) ?? false
                DispatchQueue.main.async {
                    self?.setLoading(false)
                    if isValid {
                        self?.showStatus("Login successful! ✅ (Offline verification)", isError: false)
                        self?.passwordTextField.text = ""
                    } else {
                        self?.showStatus("Invalid password ❌", isError: true)
                    }
                }
            } catch {
                DispatchQueue.main.async {
                    self?.setLoading(false)
                    self?.showStatus("Login failed: \(error.localizedDescription)", isError: true)
                }
            }
        }
    }
    
    @objc private func changePasswordTapped() {
        guard let username = usernameTextField.text, !username.isEmpty else {
            showStatus("Please enter a username", isError: true)
            return
