        let alert = UIAlertController(title: "Change Password", message: "Enter your current and new password", preferredStyle: .alert)
        
        alert.addTextField { tf in
            tf.placeholder = "Current Password"
            tf.isSecureTextEntry = true
        }
        alert.addTextField { tf in
            tf.placeholder = "New Password (min 8 chars)"
            tf.isSecureTextEntry = true
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Change", style: .default) { [weak self] _ in
            guard let oldPassword = alert.textFields?[0].text, !oldPassword.isEmpty,
                  let newPassword = alert.textFields?[1].text, !newPassword.isEmpty else {
                self?.showStatus("Please fill in both fields", isError: true)
                return
            }
            
            self?.setLoading(true)
            
            DispatchQueue.global(qos: .userInitiated).async {
                do {
                    try self?.passwordManager.updatePassword(username: username, oldPassword: oldPassword, newPassword: newPassword)
                    DispatchQueue.main.async {
                        self?.setLoading(false)
                        self?.showStatus("Password changed successfully! ✅", isError: false)
                    }
                } catch {
                    DispatchQueue.main.async {
                        self?.setLoading(false)
                        self?.showStatus("Change failed: \(error.localizedDescription)", isError: true)
                    }
                }
            }
        })
        
        present(alert, animated: true)
    }
    
    @objc private func deleteUserTapped() {
        guard let username = usernameTextField.text, !username.isEmpty else {
            showStatus("Please enter a username", isError: true)
            return
        }
        
        guard passwordManager.userExists(username: username) else {
            showStatus("User '\(username)' not found", isError: true)
            return
        }
        
        let alert = UIAlertController(title: "Delete User", message: "Are you sure you want to delete '\(username)'?", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Delete", style: .destructive) { [weak self] _ in
            self?.passwordManager.deleteUser(username: username)
            self?.showStatus("User '\(username)' deleted", isError: false)
            self?.usernameTextField.text = ""
            self?.passwordTextField.text = ""
            self?.updateRegisteredUsersLabel()
        })
        present(alert, animated: true)
    }
    
    private func showStatus(_ message: String, isError: Bool) {
        statusLabel.text = message
        statusLabel.textColor = isError ? .systemRed : .systemGreen
        
        // Auto-clear after 5 seconds
        DispatchQueue.main.asyncAfter(deadline: .now() + 5) { [weak self] in
            if self?.statusLabel.text == message {
                self?.statusLabel.text = ""
            }
        }
    }
    
    private func setLoading(_ loading: Bool) {
        if loading {
            activityIndicator.startAnimating()
        } else {
            activityIndicator.stopAnimating()
        }
        registerButton.isEnabled = !loading
        loginButton.isEnabled = !loading
        changePasswordButton.isEnabled = !loading
        deleteUserButton.isEnabled = !loading
    }
    
    private func updateRegisteredUsersLabel() {
        let users = passwordManager.registeredUsers()
        if users.isEmpty {
            registeredUsersLabel.text = "Registered Users: None"
        } else {
            registeredUsersLabel.text = "Registered Users: \(users.joined(separator: ", "))"
        }
    }
