// MARK: - Unit Tests (can be run in a test target)

class PasswordStorageTests {
    
    static func runAllTests() {
        testRegistrationAndVerification()
        testWrongPassword()
        testPasswordUpdate()
        testUserDeletion()
        testConstantTimeComparison()
        testSaltUniqueness()
        testPasswordValidation()
        print("✅ All tests passed!")
    }
    
    static func testRegistrationAndVerification() {
        let manager = PasswordStorageManager.shared
        let username = "test_user_\(UUID().uuidString.prefix(8))"
        let password = "SecureP@ssw0rd!"
        
        do {
            try manager.registerUser(username: username, password: password)
            let isValid = try manager.verifyPassword(username: username, password: password)
            assert(isValid, "Password verification should succeed")
            manager.deleteUser(username: username)
            print("  ✓ Registration and verification test passed")
        } catch {
            assertionFailure("Test failed: \(error)")
        }
    }
    
    static func testWrongPassword() {
        let manager = PasswordStorageManager.shared
        let username = "test_wrong_\(UUID().uuidString.prefix(8))"
        
        do {
            try manager.registerUser(username: username, password: "CorrectPassword123!")
            let isValid = try manager.verifyPassword(username: username, password: "WrongPassword123!")
            assert(!isValid, "Wrong password should not verify")
            manager.deleteUser(username: username)
            print("  ✓ Wrong password test passed")
        } catch {
            assertionFailure("Test failed: \(error)")
        }
    }
    
    static func testPasswordUpdate() {
        let manager = PasswordStorageManager.shared
        let username = "test_update_\(UUID().uuidString.prefix(8))"
        
        do {
            try manager.registerUser(username: username, password: "OldPassword123!")
            try manager.updatePassword(username: username, oldPassword: "OldPassword123!", newPassword: "NewPassword456!")
            
            let oldValid = try manager.verifyPassword(username: username, password: "OldPassword123!")
            assert(!oldValid, "Old password should no longer work")
            
            let newValid = try manager.verifyPassword(username: username, password: "NewPassword456!")
            assert(newValid, "New password should work")
            
            manager.deleteUser(username: username)
            print("  ✓ Password update test passed")
        } catch {
            assertionFailure("Test failed: \(error)")
        }
    }
    
    static func testUserDeletion() {
        let manager = PasswordStorageManager.shared
        let username = "test_delete_\(UUID().uuidString.prefix(8))"
        
        do {
            try manager.registerUser(username: username, password: "DeleteMe123!")
            assert(manager.userExists(username: username), "User should exist")
            
            manager.deleteUser(username: username)
            assert(!manager.userExists(username: username), "User should not exist after deletion")
            print("  ✓ User deletion test passed")
        } catch {
            assertionFailure("Test failed: \(error)")
        }
    }
    
    static func testConstantTimeComparison() {
        let data1 = Data([1, 2, 3, 4, 5])
        let data2 = Data([1, 2, 3, 4, 5])
        let data3 = Data([1, 2, 3, 4, 6])
        let data4 = Data([1, 2, 3])
        
        assert(CryptoUtils.constantTimeCompare(data1, data2), "Equal data should match")
        assert(!CryptoUtils.constantTimeCompare(data1, data3), "Different data should not match")
        assert(!CryptoUtils.constantTimeCompare(data1, data4), "Different length data should not match")
        print("  ✓ Constant-time comparison test passed")
    }
    
    static func testSaltUniqueness() {
        let salt1 = CryptoUtils.generateSalt()
        let salt2 = CryptoUtils.generateSalt()
        
        assert(salt1 != nil, "Salt generation should succeed")
        assert(salt2 != nil, "Salt generation should succeed")
        assert(salt1 != salt2, "Two salts should be different")
        assert(salt1!.count == 32, "Salt should be 32 bytes")
        print("  ✓ Salt uniqueness test passed")
    }
    
    static func testPasswordValidation() {
        let manager = PasswordStorageManager.shared
        let username = "test_validation_\(UUID().uuidString.prefix(8))"
        
        // Too short
        do {
            try manager.registerUser(username: username, password: "short")
            assertionFailure("Should have thrown for short password")
        } catch let error as PasswordStorageError {
            assert(error == .passwordTooShort, "Should be passwordTooShort error")
        } catch {
            assertionFailure("Unexpected error: \(error)")
        }
        
        print("  ✓ Password validation test passed")
    }
}